function calculateDateFromRecurrence(year, recurrence) {
    if (recurrence.type === 'fixed') {
        return new Date(year, recurrence.month - 1, recurrence.day);
    } else if (recurrence.type === 'nthDay') {
        // recurrence: { type: 'nthDay', month: 5, dayOfWeek: 1, nth: 1 } for 1st Monday in May
        let date = new Date(year, recurrence.month - 1, 1);
        let dayOfWeek = date.getDay(); // 0=Sunday, 1=Monday...
        let targetDayOfWeek = recurrence.dayOfWeek;

        let firstTargetDay = date.getDate() + (targetDayOfWeek - dayOfWeek + 7) % 7;
        let resultDate = new Date(year, recurrence.month - 1, firstTargetDay);

        // Add (nth-1) weeks
        resultDate.setDate(resultDate.getDate() + (recurrence.nth - 1) * 7);
        return resultDate;
    } else if (recurrence.type === 'lastDay') {
        // recurrence: { type: 'lastDay', month: 8, dayOfWeek: 1 } for last Monday in August
        let date = new Date(year, recurrence.month, 0); // Last day of previous month = day 0 of current month
        let dayOfWeek = date.getDay();
        let targetDayOfWeek = recurrence.dayOfWeek;

        let daysToSubtract = (dayOfWeek - targetDayOfWeek + 7) % 7;
        date.setDate(date.getDate() - daysToSubtract);
        return date;
    }
    return null;
}

const today = new Date();
const currentYear = today.getFullYear();

const userLocation = inputs.userLocation.toLowerCase();
const culturalFocus = inputs.culturalFocus.toLowerCase().split(',').map(s => s.trim()).filter(s => s);
const eventCategoryInterest = inputs.eventCategoryInterest.toLowerCase().split(',').map(s => s.trim()).filter(s => s);
const planningLeadTimeDays = Number(inputs.planningLeadTime);
const timeHorizonMonths = Number(inputs.timeHorizon);
const preferredAudience = inputs.preferredAudience ? inputs.preferredAudience.toLowerCase().split(',').map(s => s.trim()).filter(s => s) : [];
const eventSizePreference = inputs.eventSizePreference ? inputs.eventSizePreference.toLowerCase().split(',').map(s => s.trim()).filter(s => s) : [];

const minPlanningDate = new Date(today.setDate(today.getDate() + planningLeadTimeDays));
const maxPlanningDate = new Date(minPlanningDate);
maxPlanningDate.setMonth(minPlanningDate.getMonth() + timeHorizonMonths);

const eventsTemplate = [
    { name: "New Year's Day", description: "Global celebration of the new year.", type: "Holiday", categories: ["social"], audience: ["community-wide"], size: ["international", "national"], locations: ["global"], culturalTags: ["national", "traditional", "social"], recurrence: { type: "fixed", month: 1, day: 1 } },
    { name: "Valentine's Day", description: "Day of love and affection.", type: "Observance", categories: ["social", "romantic"], audience: ["adults", "youth"], size: ["international", "regional"], locations: ["global"], culturalTags: ["modern", "traditional", "social"], recurrence: { type: "fixed", month: 2, day: 14 } },
    { name: "International Women's Day", description: "Global day celebrating the social, economic, cultural, and political achievements of women.", type: "Observance", categories: ["social", "advocacy", "history"], audience: ["community-wide", "adults"], size: ["international"], locations: ["global"], culturalTags: ["modern", "social", "historical"], recurrence: { type: "fixed", month: 3, day: 8 } },
    { name: "Earth Day", description: "Worldwide annual event to demonstrate support for environmental protection.", type: "Observance", categories: ["nature", "environmental", "advocacy"], audience: ["community-wide", "family-friendly"], size: ["international"], locations: ["global"], culturalTags: ["modern", "social"], recurrence: { type: "fixed", month: 4, day: 22 } },
    { name: "May Day Bank Holiday (UK)", description: "Public holiday in the UK, traditionally celebrating spring.", type: "Holiday", categories: ["social", "traditional"], audience: ["community-wide", "family-friendly"], size: ["national"], locations: ["uk", "london, uk", "england", "scotland", "wales"], culturalTags: ["national", "traditional", "historical"], recurrence: { type: "nthDay", month: 5, dayOfWeek: 1, nth: 1 } },
    { name: "Notting Hill Carnival (London)", description: "Europe's biggest street festival celebrating Caribbean culture.", type: "Festival", categories: ["music", "food", "art", "social"], audience: ["community-wide", "adults", "youth"], size: ["regional", "international"], locations: ["london, uk"], culturalTags: ["ethnic", "music", "traditional", "social"], recurrence: { type: "lastDay", month: 8, dayOfWeek: 1 } }, // Last Monday in August
    { name: "Sakura Festival (Japan)", description: "Celebration of spring and cherry blossoms across Japan.", type: "Festival", categories: ["nature", "social", "traditional"], audience: ["community-wide", "family-friendly"], size: ["national", "regional"], locations: ["japan", "kyoto, japan", "tokyo, japan"], culturalTags: ["national", "traditional", "seasonal"], recurrence: { type: "approximate", month: 4, day: 10 } }, // Simplified, varies by region
    { name: "Golden Week (Japan)", description: "A series of national holidays in Japan, popular for travel.", type: "Holiday Series", categories: ["social", "travel", "national"], audience: ["community-wide", "family-friendly"], size: ["national"], locations: ["japan"], culturalTags: ["national", "traditional"], recurrence: { type: "fixed", month: 4, day: 29 } }, // Start date
    { name: "Independence Day (USA)", description: "National holiday celebrating the signing of the Declaration of Independence.", type: "Holiday", categories: ["social", "patriotic", "history"], audience: ["community-wide", "family-friendly"], size: ["national"], locations: ["usa", "new york city, usa", "california, usa"], culturalTags: ["national", "historical", "traditional"], recurrence: { type: "fixed", month: 7, day: 4 } },
    { name: "Thanksgiving Day (USA)", description: "Federal holiday, a day of giving thanks.", type: "Holiday", categories: ["social", "food", "family"], audience: ["community-wide", "family-friendly"], size: ["national"], locations: ["usa", "new york city, usa", "california, usa"], culturalTags: ["national", "traditional", "social"], recurrence: { type: "nthDay", month: 11, dayOfWeek: 4, nth: 4 } }, // 4th Thursday in November
    { name: "Oktoberfest (Munich)", description: "World's largest Volksfest, featuring beer, food, and traditional Bavarian culture.", type: "Festival", categories: ["food", "social", "music"], audience: ["adults"], size: ["international", "regional"], locations: ["munich, germany", "germany"], culturalTags: ["traditional", "ethnic", "social"], recurrence: { type: "approximate", month: 9, day: 20 } }, // Approx start date, runs into Oct
    { name: "Diwali (Festival of Lights)", description: "Hindu festival of lights, celebrated by millions worldwide.", type: "Religious Holiday", categories: ["religious", "social", "traditional"], audience: ["community-wide", "family-friendly"], size: ["international", "national"], locations: ["global", "india", "uk", "usa"], culturalTags: ["religious", "traditional", "spiritual"], recurrence: { type: "approximate", month: 10, day: 30 } }, // Highly variable, simplified to late Oct/early Nov
    { name: "Christmas Day", description: "Christian holiday celebrating the birth of Jesus.", type: "Holiday", categories: ["religious", "social", "family"], audience: ["community-wide", "family-friendly"], size: ["international"], locations: ["global"], culturalTags: ["religious", "traditional", "social"], recurrence: { type: "fixed", month: 12, day: 25 } },
    { name: "Local Harvest Festival", description: "Community celebration of local produce and autumn.", type: "Festival", categories: ["food", "nature", "community"], audience: ["community-wide", "family-friendly"], size: ["small community", "regional"], locations: ["*"], culturalTags: ["traditional", "seasonal", "social"], recurrence: { type: "approximate", month: 9, day: 15 } },
    { name: "Annual Art Exhibition", description: "Showcasing local and regional artists.", type: "Exhibition", categories: ["art", "cultural"], audience: ["adults", "youth"], size: ["regional", "small community"], locations: ["*"], culturalTags: ["artistic", "cultural"], recurrence: { type: "approximate", month: 5, day: 20 } },
    { name: "Historical Reenactment Day", description: "Commemorating significant historical events with live reenactments.", type: "Event", categories: ["history", "education"], audience: ["family-friendly", "youth", "adults"], size: ["regional", "small community"], locations: ["*"], culturalTags: ["historical", "educational"], recurrence: { type: "approximate", month: 8, day: 5 } }
];

let personalizedCalendar = [];
const currentYearPlusOne = currentYear + 1;

for (let year = currentYear; year <= currentYearPlusOne; year++) {
    eventsTemplate.forEach(template => {
        let eventDate = null;
        if (template.recurrence.type === 'approximate' || template.recurrence.type === 'fixedSeries') {
            eventDate = new Date(year, template.recurrence.month - 1, template.recurrence.day || template.recurrence.dayStart);
        } else {
            eventDate = calculateDateFromRecurrence(year, template.recurrence);
        }

        if (eventDate) {
            // Handle Golden Week as a series, if necessary for planning (simplified as start date for now)
            if (template.name === 'Golden Week (Japan)' && eventDate.getMonth() !== 3) { // Check if April
              eventDate = new Date(year, 3, 29); // April 29th
            }

            if (eventDate >= minPlanningDate && eventDate <= maxPlanningDate) {
                let relevanceScore = 0;
                const locationMatch = template.locations.some(loc => loc === 'global' || loc === userLocation || userLocation.includes(loc));

                if (locationMatch) relevanceScore += 3;

                const culturalMatch = culturalFocus.some(focus => template.culturalTags.includes(focus));
                if (culturalMatch) relevanceScore += 2;

                const categoryMatch = eventCategoryInterest.some(cat => template.categories.includes(cat));
                if (categoryMatch) relevanceScore += 2;

                if (preferredAudience.length > 0) {
                    const audienceMatch = preferredAudience.some(aud => template.audience.includes(aud));
                    if (audienceMatch) relevanceScore += 1;
                } else {
                    relevanceScore += 0.5; // Small bonus if no audience specified, implies broader appeal
                }

                if (eventSizePreference.length > 0) {
                    const sizeMatch = eventSizePreference.some(size => template.size.includes(size));
                    if (sizeMatch) relevanceScore += 1;
                } else {
                    relevanceScore += 0.5; // Small bonus if no size specified
                }

                // Prioritize exact location matches more
                if (template.locations.includes(userLocation)) relevanceScore += 1;

                if (relevanceScore > 0) {
                    personalizedCalendar.push({
                        date: eventDate.toISOString().split('T')[0],
                        name: template.name,
                        description: template.description,
                        type: template.type,
                        relevanceScore: relevanceScore
                    });
                }
            }
        }
    });
}

// Sort by date, then by relevance score (descending)
personalizedCalendar.sort((a, b) => {
    const dateA = new Date(a.date);
    const dateB = new Date(b.date);
    if (dateA - dateB !== 0) {
        return dateA - dateB;
    }
    return b.relevanceScore - a.relevanceScore;
});

// Cap the number of events to a reasonable display limit (e.g., 50 events)
const maxEventsDisplay = 50;
if (personalizedCalendar.length > maxEventsDisplay) {
    personalizedCalendar = personalizedCalendar.slice(0, maxEventsDisplay);
}

// Return the structured output
return {
    eventCount: personalizedCalendar.length,
    personalizedCalendar: personalizedCalendar // This will be the complex object
};
